-- Create "finance_facts" table
CREATE TABLE "finance_facts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "fact_no" character varying NOT NULL,
  "fact_type" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "counterparty_type" character varying NOT NULL,
  "counterparty_id" bigint NULL,
  "amount" numeric(20,6) NOT NULL,
  "currency" character varying NOT NULL DEFAULT 'CNY',
  "source_type" character varying NULL,
  "source_id" bigint NULL,
  "source_line_id" bigint NULL,
  "idempotency_key" character varying NOT NULL,
  "occurred_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "settled_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "finance_facts_amount_positive" CHECK (amount > (0)::numeric),
  CONSTRAINT "finance_facts_counterparty_allowed" CHECK ((counterparty_type)::text = ANY ((ARRAY['CUSTOMER'::character varying, 'SUPPLIER'::character varying, 'OTHER'::character varying])::text[])),
  CONSTRAINT "finance_facts_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'POSTED'::character varying, 'SETTLED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "finance_facts_type_allowed" CHECK ((fact_type)::text = ANY ((ARRAY['RECEIVABLE'::character varying, 'PAYABLE'::character varying, 'INVOICE'::character varying, 'PAYMENT'::character varying, 'RECONCILIATION'::character varying])::text[]))
);
-- Create index "financefact_counterparty_type_counterparty_id" to table: "finance_facts"
CREATE INDEX "financefact_counterparty_type_counterparty_id" ON "finance_facts" ("counterparty_type", "counterparty_id");
-- Create index "financefact_fact_no" to table: "finance_facts"
CREATE UNIQUE INDEX "financefact_fact_no" ON "finance_facts" ("fact_no");
-- Create index "financefact_fact_type_status" to table: "finance_facts"
CREATE INDEX "financefact_fact_type_status" ON "finance_facts" ("fact_type", "status");
-- Create index "financefact_idempotency_key" to table: "finance_facts"
CREATE UNIQUE INDEX "financefact_idempotency_key" ON "finance_facts" ("idempotency_key");
-- Create index "financefact_source_type_source_id_source_line_id" to table: "finance_facts"
CREATE INDEX "financefact_source_type_source_id_source_line_id" ON "finance_facts" ("source_type", "source_id", "source_line_id");
-- Create "outsourcing_facts" table
CREATE TABLE "outsourcing_facts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "fact_no" character varying NOT NULL,
  "fact_type" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "subject_type" character varying NOT NULL,
  "subject_id" bigint NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "supplier_id" bigint NULL,
  "supplier_name" character varying NULL,
  "source_type" character varying NULL,
  "source_id" bigint NULL,
  "source_line_id" bigint NULL,
  "idempotency_key" character varying NOT NULL,
  "occurred_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "lot_id" bigint NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "outsourcing_facts_inventory_lots_outsourcing_facts" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_facts_units_outsourcing_facts" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_facts_warehouses_outsourcing_facts" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_facts_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "outsourcing_facts_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'POSTED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "outsourcing_facts_subject_allowed" CHECK ((subject_type)::text = ANY ((ARRAY['MATERIAL'::character varying, 'PRODUCT'::character varying])::text[])),
  CONSTRAINT "outsourcing_facts_type_allowed" CHECK ((fact_type)::text = ANY ((ARRAY['MATERIAL_ISSUE'::character varying, 'RETURN_RECEIPT'::character varying, 'SETTLEMENT'::character varying])::text[]))
);
-- Create index "outsourcingfact_fact_no" to table: "outsourcing_facts"
CREATE UNIQUE INDEX "outsourcingfact_fact_no" ON "outsourcing_facts" ("fact_no");
-- Create index "outsourcingfact_fact_type_status" to table: "outsourcing_facts"
CREATE INDEX "outsourcingfact_fact_type_status" ON "outsourcing_facts" ("fact_type", "status");
-- Create index "outsourcingfact_idempotency_key" to table: "outsourcing_facts"
CREATE UNIQUE INDEX "outsourcingfact_idempotency_key" ON "outsourcing_facts" ("idempotency_key");
-- Create index "outsourcingfact_source_type_source_id_source_line_id" to table: "outsourcing_facts"
CREATE INDEX "outsourcingfact_source_type_source_id_source_line_id" ON "outsourcing_facts" ("source_type", "source_id", "source_line_id");
-- Create index "outsourcingfact_subject_type_subject_id_warehouse_id_lot_id" to table: "outsourcing_facts"
CREATE INDEX "outsourcingfact_subject_type_subject_id_warehouse_id_lot_id" ON "outsourcing_facts" ("subject_type", "subject_id", "warehouse_id", "lot_id");
-- Create index "outsourcingfact_supplier_id" to table: "outsourcing_facts"
CREATE INDEX "outsourcingfact_supplier_id" ON "outsourcing_facts" ("supplier_id");
-- Create "production_facts" table
