  CONSTRAINT "production_facts_type_allowed" CHECK ((fact_type)::text = ANY ((ARRAY['MATERIAL_ISSUE'::character varying, 'FINISHED_GOODS_RECEIPT'::character varying, 'REWORK'::character varying])::text[]))
);
-- Create index "productionfact_fact_no" to table: "production_facts"
CREATE UNIQUE INDEX "productionfact_fact_no" ON "production_facts" ("fact_no");
