-- Create "shipments" table
CREATE TABLE "shipments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "shipment_no" character varying NOT NULL,
  "customer_snapshot" character varying NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "idempotency_key" character varying NOT NULL,
  "planned_ship_at" timestamptz NULL,
  "shipped_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "customer_id" bigint NULL,
  "sales_order_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "shipments_customers_shipments" FOREIGN KEY ("customer_id") REFERENCES "customers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "shipments_sales_orders_shipments" FOREIGN KEY ("sales_order_id") REFERENCES "sales_orders" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "shipments_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'SHIPPED'::character varying, 'CANCELLED'::character varying])::text[]))
);
-- Create index "shipment_customer_id" to table: "shipments"
CREATE INDEX "shipment_customer_id" ON "shipments" ("customer_id");
-- Create index "shipment_idempotency_key" to table: "shipments"
CREATE UNIQUE INDEX "shipment_idempotency_key" ON "shipments" ("idempotency_key");
-- Create index "shipment_sales_order_id" to table: "shipments"
CREATE INDEX "shipment_sales_order_id" ON "shipments" ("sales_order_id");
-- Create index "shipment_shipment_no" to table: "shipments"
CREATE UNIQUE INDEX "shipment_shipment_no" ON "shipments" ("shipment_no");
-- Create index "shipment_status" to table: "shipments"
CREATE INDEX "shipment_status" ON "shipments" ("status");
-- Create "shipment_items" table
