  CONSTRAINT "shipment_items_sales_order_items_shipment_items" FOREIGN KEY ("sales_order_item_id") REFERENCES "sales_order_items" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "shipment_items_shipments_items" FOREIGN KEY ("shipment_id") REFERENCES "shipments" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "shipment_items_units_shipment_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "shipment_items_warehouses_shipment_items" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "shipment_items_quantity_positive" CHECK (quantity > (0)::numeric)
);
-- Create index "shipmentitem_product_id_warehouse_id_lot_id" to table: "shipment_items"
