-- Create "stock_reservations" table
CREATE TABLE "stock_reservations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "reservation_no" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'ACTIVE',
  "quantity" numeric(20,6) NOT NULL,
  "idempotency_key" character varying NOT NULL,
  "reserved_at" timestamptz NOT NULL,
  "released_at" timestamptz NULL,
  "consumed_at" timestamptz NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "lot_id" bigint NULL,
  "product_id" bigint NOT NULL,
  "sales_order_id" bigint NULL,
  "sales_order_item_id" bigint NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "stock_reservations_inventory_lots_stock_reservations" FOREIGN KEY ("lot_id") REFERENCES "inventory_lots" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "stock_reservations_products_stock_reservations" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "stock_reservations_sales_order_items_stock_reservations" FOREIGN KEY ("sales_order_item_id") REFERENCES "sales_order_items" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "stock_reservations_sales_orders_stock_reservations" FOREIGN KEY ("sales_order_id") REFERENCES "sales_orders" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "stock_reservations_units_stock_reservations" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "stock_reservations_warehouses_stock_reservations" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "stock_reservations_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "stock_reservations_status_allowed" CHECK ((status)::text = ANY ((ARRAY['ACTIVE'::character varying, 'RELEASED'::character varying, 'CONSUMED'::character varying, 'CANCELLED'::character varying])::text[]))
);
-- Create index "stockreservation_idempotency_key" to table: "stock_reservations"
CREATE UNIQUE INDEX "stockreservation_idempotency_key" ON "stock_reservations" ("idempotency_key");
-- Create index "stockreservation_product_id_warehouse_id_lot_id" to table: "stock_reservations"
CREATE INDEX "stockreservation_product_id_warehouse_id_lot_id" ON "stock_reservations" ("product_id", "warehouse_id", "lot_id");
-- Create index "stockreservation_reservation_no" to table: "stock_reservations"
CREATE UNIQUE INDEX "stockreservation_reservation_no" ON "stock_reservations" ("reservation_no");
-- Create index "stockreservation_sales_order_id" to table: "stock_reservations"
CREATE INDEX "stockreservation_sales_order_id" ON "stock_reservations" ("sales_order_id");
-- Create index "stockreservation_sales_order_item_id" to table: "stock_reservations"
